155	// TestInfrastructureFailureDoesNotEscalate asserts that the
156	// infrastructure-failure check used by the tier-escalation loop in
157	// runAgentExecuteLoop short-circuits without consuming escalation
158	// budget. We verify the contract that:
159	//   - IsInfrastructureFailure(execution_failed, "502 Bad Gateway") is true,
160	//     so the loop body's infrastructure branch fires (deferred + RetryAfter).
161	//   - IsInfrastructureFailure(execution_failed, "TestFoo failed") is false,
162	//     so the loop falls through to mark the harness unhealthy and try the
163	//     next tier.
164	//
165	// This is a contract test — the actual tier-escalation closure is built
166	// inline in runAgentExecuteLoop. The two-arm decision in that closure
167	// (defer-vs-escalate) is driven entirely by IsInfrastructureFailure.
168	func TestInfrastructureFailureDoesNotEscalate(t *testing.T) {
169		cases := []struct {
170			name   string
171			status string
172			detail string
173			// wantInfra=true means "defer with retry-after, do not escalate";
174			// wantInfra=false means "escalate to next tier".
175			wantInfra bool
176		}{
177			{"502 from provider triggers defer", agent.ExecuteBeadStatusExecutionFailed, "POST /v1/chat: 502 Bad Gateway", true},
178			{"connection refused triggers defer", agent.ExecuteBeadStatusExecutionFailed, "dial tcp: connection refused", true},
179			{"401 unauthorized triggers defer", agent.ExecuteBeadStatusExecutionFailed, "401 Unauthorized", true},
180			{"plain test failure does NOT defer (escalates)", agent.ExecuteBeadStatusExecutionFailed, "TestFoo: assertion failed", false},
181			{"structural failure escalates but is not infrastructure", "structural_validation_failed", "anything 502", false},
182		}
183		for _, tc := range cases {
184			t.Run(tc.name, func(t *testing.T) {
185				got := escalation.IsInfrastructureFailure(tc.status, tc.detail)
186				if got != tc.wantInfra {
187					t.Fatalf("IsInfrastructureFailure(%q, %q) = %v, want %v", tc.status, tc.detail, got, tc.wantInfra)
