// StopCondition is the typed work-drain terminal decision vocabulary. Keep
// these values stable; evidence and operator surfaces derive from them.
type StopCondition string

const (
    StopConditionDrained    StopCondition = "Drained"
    StopConditionOnce       StopCondition = "Once"
    StopConditionSignal     StopCondition = "Signal"
    StopConditionBudget     StopCondition = "Budget"
    StopConditionNoProgress StopCondition = "NoProgress"
    StopConditionBlocked    StopCondition = "Blocked"
)

// StopInput describes one possible terminal drain decision point.
type StopInput struct {
    ContextErr   error
    NoReadyWork  bool
    Once         bool
    PollInterval time.Duration
    Budget       bool
    NoProgress   bool
    Blocked      bool
}

// StopDecision is the classified terminal decision plus the legacy-compatible
// loop.end exit_reason string.
type StopDecision struct {
    Condition  StopCondition
    ExitReason string
}

// ClassifyStop maps scattered drain-loop terminal checks to a single typed
// vocabulary while preserving existing exit_reason strings.
func ClassifyStop(in StopInput) (StopDecision, bool) {
    switch {
    case in.ContextErr != nil:
        return StopDecision{
            Condition:  StopConditionSignal,
            ExitReason: signalExitReason(in.ContextErr),
        }, true
    case in.Budget:
        return StopDecision{Condition: StopConditionBudget, ExitReason: "budget"}, true
    // ... other cases
    }
}
```

**Key Points:**
- `StopConditionBudget = "Budget"` is the typed condition for cost-cap stops
- When `Budget: true` is passed to `ClassifyStop()`, it returns `StopCondition="Budget"` with `ExitReason="budget"`
- This is the **ddx-89ab3fda** feature that introduced typed Budget as a StopCondition

### 4. **CostCapTracker Implementation** (cli/internal/escalation/infrastructure.go lines 114-207)

```go
// CostCapTracker accumulates billed cost for a single execute-loop run
// and reports when accumulated spend has reached the configured cap.
// Safe for concurrent use across goroutines (workers may call Add and
// Tripped concurrently).
//
// MaxUSD == 0 disables the cap; Tripped always returns (_, false). The
// Lookup callback decides which harnesses contribute to the running
// total — local and subscription-bundled providers should be excluded
// (see CountsTowardCostCap).
type CostCapTracker struct {
    MaxUSD float64
    Lookup HarnessBilledLookup

    mu    sync.Mutex
    spent float64
    // cache memoizes Lookup results so we do not rebuild a service for
    // every reported attempt. Protected by mu.
    cache map[string]bool
}

// NewCostCapTracker constructs a tracker with the given dollar cap and
// lookup. Pass maxUSD <= 0 to disable the cap. A nil lookup is treated
// as "count by default" — every harness contributes.
func NewCostCapTracker(maxUSD float64, lookup HarnessBilledLookup) *CostCapTracker {
    return &CostCapTracker{
        MaxUSD: maxUSD,
        Lookup: lookup,
        cache:  map[string]bool{},
    }
}

// Add accumulates costUSD against the running total when harnessName's
// billing class counts toward the cap. Non-positive cost is ignored.
func (t *CostCapTracker) Add(harnessName string, costUSD float64) {
    if costUSD <= 0 {
        return
    }
    if !t.counts(harnessName) {
        return
    }
    t.mu.Lock()
    t.spent += costUSD
    t.mu.Unlock()
}

// Tripped reports whether the accumulated spend has reached MaxUSD. When
// MaxUSD <= 0 the cap is disabled and Tripped returns (_, false).
// Returns the formatted operator-facing detail string when tripped so
// callers can populate a stop-the-loop ExecuteBeadReport.
func (t *CostCapTracker) Tripped() (string, bool) {
    if t.MaxUSD <= 0 {
        return "", false
    }
    t.mu.Lock()
    spent := t.spent
    t.mu.Unlock()
    if spent < t.MaxUSD {
        return "", false
    }
    return fmt.Sprintf("cost cap reached: $%.2f billed >= $%.2f cap; raise the cap or set 0 to disable. Subscription and local providers do not count.", spent, t.MaxUSD), true
}
```

**Key Points:**
- Thread-safe with mutex protection
- `counts()` method uses memoized lookup to decide if a harness contributes
- `Add()` only accumulates costs that pass the `counts()` check
- `Tripped()` returns a formatted detail message when cap is exceeded

