                    Actor:     in.Assignee,
                    Source:    "ddx agent execute-loop",
                    CreatedAt: now().UTC(),
                })
                if in.Log != nil {
                    _, _ = fmt.Fprintf(in.Log, "review cost cap deferred (%s %s): %s\n", in.Bead.ID, report.ResultRev, detail)
