393	// applyReviewTriageDecision runs the triage policy after a BLOCK or
394	// REQUEST_CHANGES review verdict has been recorded for `beadID`. It reads
395	// prior review events to compute the BLOCK count, biases the result toward
396	// re-attempt when the latest BLOCK was paired with a degraded reviewer
397	// (kind:review-pairing-degraded), then applies the chosen action by writing
398	// metadata, labels, and a kind:triage-decision event.
399	//
400	// Errors from the underlying store are best-effort: callers continue
401	// regardless so a triage-side failure cannot strand a bead in an
402	// inconsistent review state. This callout previously lived as a method on
403	// ExecuteBeadWorker; the C3
404	// extraction (ddx-a921ff01) moves it inside the post-merge-review pipeline
405	// driven by RunPostMergeReview / try.Attempt.
406	func applyReviewTriageDecision(store ExecuteBeadLoopStore, beadID, actor string, now time.Time, currentTier string) error {
407		events, err := store.Events(beadID)
408		if err != nil {
409			return err
410		}
411	
412		var blockTimestamps []time.Time
413		var pairingDegraded []time.Time
414		for _, ev := range events {
415			switch {
416			case ev.Kind == "review" && strings.TrimSpace(ev.Summary) == "BLOCK":
417				blockTimestamps = append(blockTimestamps, ev.CreatedAt)
418			case ev.Kind == ReviewPairingDegradedEventKind:
419				pairingDegraded = append(pairingDegraded, ev.CreatedAt)
420			}
421		}
422	
423		// History excludes the current attempt. The just-appended BLOCK (if any)
424		// is the last entry in blockTimestamps and must not be counted as prior
425		// history per triage.Decide()'s contract.
426		historyCount := len(blockTimestamps)
427		if historyCount > 0 {
428			historyCount--
429		}
430		history := make([]triage.FailureMode, 0, historyCount)
431		for i := 0; i < historyCount; i++ {
432			history = append(history, triage.FailureModeReviewBlock)
433		}
434	
435		policy := triage.DefaultPolicy()
436		action := policy.Decide(beadID, triage.FailureModeReviewBlock, history)
437	
438		pairedDegraded := latestBlockPairedDegraded(blockTimestamps, pairingDegraded)
439		if pairedDegraded && action == triage.ActionEscalateTier {
440			action = triage.ActionReAttemptWithContext
441		}
442	
443		return applyTriageAction(store, beadID, actor, now, action, currentTier, pairedDegraded)
444	}
