446	// latestBlockPairedDegraded reports whether the most recent BLOCK event was
447	// paired with a review-pairing-degraded event from the same attempt window
448	// (between the previous BLOCK and this one).
449	func latestBlockPairedDegraded(blocks, pairing []time.Time) bool {
450		if len(blocks) == 0 || len(pairing) == 0 {
451			return false
452		}
453		latest := blocks[len(blocks)-1]
454		var prev time.Time
455		if len(blocks) >= 2 {
456			prev = blocks[len(blocks)-2]
457		}
458		for _, t := range pairing {
459			if t.After(prev) && !t.After(latest) {
460				return true
461			}
462		}
463		return false
464	}
